use indexmap::IndexMap;
use std::collections::HashMap;

type ConfigStore = IndexMap<String, u32>;

fn process_handsake_config() -> Result<ConfigStore, Box<dyn std::error::Error>> {
    let mut config: ConfigStore = IndexMap::new();

    config.insert("client_id".to_string(), 100);
    config.insert("server_version".to_string(), 2024);

    let mut lookup_data: HashMap<String, u32> = std::collections::HashMap::new();
    for (key, value) in config.iter() {
        println!("Found key: {}, Value: {}", key, value);
        lookup_data.insert(key.clone(), *value);
    }

    config.insert("max_retries".to_string(), 3);
    let new_val = config.get("server_version").copied().unwrap_or(0);

    if new_val > 2000 {
        println!("Successfully retrieved high version number: {}", new_val);
    }

    Ok(config)
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let config = process_handsake_config()?;
    println!("nFinal configuration store contains {} entries.", config.len());
    Ok(())
}

use std::collections::HashMap;
use indexmap::IndexMap;

#[derive(Debug, Clone)]
struct FeatureVector {
    id: u64,
    embedding: Vec<f32>,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut feature_store: IndexMap<u64, FeatureVector> = IndexMap::new();

    feature_store.insert(101, FeatureVector { id: 101, embedding: vec![0.1, 0.2] });
    feature_store.insert(50, FeatureVector { id: 50, embedding: vec![-0.1, -0.2] });
    feature_store.insert(200, FeatureVector { id: 200, embedding: vec![0.3, 0.4] });

    let mut sorted_embeddings: Vec<Vec<f32>> = Vec::new();

    for (_key, vector) in feature_store.iter() {
        println!("Processing ID: {}", vector.id);
        sorted_embeddings.push(vector.embedding.clone());
    }

    println!("n--- All Processed Embeddings (Should be sorted by insertion key order) ---");
    for embedding in &sorted_embeddings {
        println!("Found vector: {:?}", embedding);
    }

    Ok(())
}

use indexmap::IndexMap;
use std::collections::HashSet;

struct Node {
    id: u32,
    name: String,
    data: i32,
}

fn get_neighbors_for_bfs(current_id: u32) -> Option<Vec<u32>> {
    let mut neighbors = Vec::new();
    if current_id == 101 {
        neighbors.push(102);
    } else if current_id == 102 {
        neighbors.push(101);
        neighbors.push(103);
    } else if current_id == 103 {
        neighbors.push(102);
    }
    if neighbors.is_empty() {
        None
    } else {
        Some(neighbors)
    }
}

fn main() {
    let mut node_store: IndexMap<u32, Node> = IndexMap::new();

    let nodes_to_add = vec![
        Node { id: 101, name: "Start".to_string(), data: 5 },
        Node { id: 102, name: "Intermediate".to_string(), data: 10 },
        Node { id: 103, name: "End".to_string(), data: 20 } 
    ];

    for node in nodes_to_add {
        node_store.insert(node.id, node);
    }

    let search_ids = vec![103, 101];
    let mut visited_ids: HashSet<u32> = HashSet::new();
    let mut queue: std::vec::Vec<u32> = search_ids.clone();

    while let Some(current_id) = queue.pop() {
        if !visited_ids.contains(&current_id) && node_store.contains_key(&current_id) {
            let current_node = node_store.get(&current_id).unwrap();
            println!("Processing Node: ID={}, Name={}", current_node.id, current_node.name);

            visited_ids.insert(current_id);

            if let Some(neighbors) = get_neighbors_for_bfs(current_id) {
                for neighbor_id in neighbors {
                    if !visited_ids.contains(&neighbor_id) && node_store.contains_key(&neighbor_id) && !queue.iter().any(|&id| id == neighbor_id) {
                        queue.push(neighbor_id);
                    }
                }
            }
        }
    }
}

use indexmap::IndexMap;
use std::fmt::{self, Display, Formatter};

struct VaultEntry {
    id: String,
    encrypted_data: Vec<u8>,
}

impl Display for VaultEntry {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        write!(f, "ID: {}", self.id)
    }
}

fn main() {
    let mut vault_index: IndexMap<String, VaultEntry> = IndexMap::new();

    let entry1 = VaultEntry {
        id: "user_alice".to_string(),
        encrypted_data: vec![10, 20, 30],
    };
    vault_index.insert(entry1.id.clone(), entry1);

    let entry2 = VaultEntry {
        id: "service_api".to_string(),
        encrypted_data: vec![40, 50, 60],
    };
    vault_index.insert(entry2.id.clone(), entry2);

    let entry3 = VaultEntry {
        id: "admin_backup".to_string(),
        encrypted_data: vec![70, 80, 90],
    };
    vault_index.insert(entry3.id.clone(), entry3);

    println!("--- Iterating in insertion order ---n");
    for (key, entry) in &vault_index {
        println!("Key: {}", key);
        println!("  Stored Data Size: {}", entry.encrypted_data.len());
    }

    let lookup_id = "service_api".to_string();
    if let Some(entry) = vault_index.get(&lookup_id) {
        println!("nSuccessfully found entry for {}: {}", lookup_id, entry);
    }
}

use indexmap::IndexMap;
use std::collections::hash_map::DefaultHasher;
use std::hash::{Hash, Hasher};

struct ConfigCache {
    params: IndexMap<String, f32>,
}

impl ConfigCache {
    fn new() -> Self {
        ConfigCache {
            params: IndexMap::new(),
        }
    }

    fn set_param(&mut self, name: String, value: f32) {
        self.params.insert(name, value);
    }

    fn get_param(&self, name: &str) -> Option<&f32> {
        self.params.get(name)
    }

    fn print_ordered_config(&self) {
        println!("--- Model Configuration (Order Preserved) ---");
        for (index, entry) in self.params.iter() {
            println!("{}: {}", index, entry);
        }
        println!("-----------------------------------------");
    }
}

fn main() {
    let mut cache = ConfigCache::new();

    cache.set_param("learning_rate".to_string(), 0.001);
    cache.set_param("batch_size".to_string(), 32.0);
    cache.set_param("activation_bias".to_string(), 0.5);

    cache.print_ordered_config();

    if let Some(rate) = cache.get_param("learning_rate") {
        println!("Successfully retrieved learning rate: {}", rate);
    }
}
